64	    private void writeAntigravity(String id, String transcript, String summaryJson)
65	        throws IOException {
66	        Path logs = tempHome
67	            .resolve(".gemini")
68	            .resolve("antigravity-cli")
69	            .resolve("brain")
70	            .resolve(id)
71	            .resolve(".system_generated")
72	            .resolve("logs");
